            var baseUrl = Environment.GetEnvironmentVariable("MOCK_SERVER_URL") ?? "http://localhost:8080";
            using var handler = new System.Net.Http.HttpClientHandler { AllowAutoRedirect = false };
            using var client = new System.Net.Http.HttpClient(handler);
            var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Post, $"{baseUrl}/fixtures/required_file_upload_missing/files/required");
            var multipartBytes = System.Text.Encoding.UTF8.GetBytes("--alef-boundary--\r\n");
            var multipartContent = new System.Net.Http.ByteArrayContent(multipartBytes);
            var mediaType = new System.Net.Http.Headers.MediaTypeHeaderValue("multipart/form-data");
            mediaType.Parameters.Add(new System.Net.Http.Headers.NameValueHeaderValue("boundary", "alef-boundary"));
            multipartContent.Headers.ContentType = mediaType;
            request.Content = multipartContent;
            var response = await client.SendAsync(request);
            Assert.Equal(422, (int)response.StatusCode);
            var bodyText = await response.Content.ReadAsStringAsync();
            var body = JsonDocument.Parse(bodyText).RootElement;
            var expectedBody = JsonDocument.Parse("{\"detail\":\"1 validation error in request\",\"errors\":[{\"input\":{},\"loc\":[\"body\",\"file\"],\"msg\":\"Field required\",\"type\":\"missing\"}],\"status\":422,\"title\":\"Request Validation Failed\",\"type\":\"https://spikard.dev/errors/validation-error\"}").RootElement;
            Assert.Equal(expectedBody.GetRawText(), body.GetRawText());
        }

        [Fact]    public async Task Test_SimpleFileUpload()
        {
            // Single file upload with text/plain content type
            var baseUrl = Environment.GetEnvironmentVariable("MOCK_SERVER_URL") ?? "http://localhost:8080";
            using var handler = new System.Net.Http.HttpClientHandler { AllowAutoRedirect = false };
            using var client = new System.Net.Http.HttpClient(handler);
            var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Post, $"{baseUrl}/fixtures/simple_file_upload/");
            var response = await client.SendAsync(request);
            Assert.Equal(200, (int)response.StatusCode);
            var bodyText = await response.Content.ReadAsStringAsync();
            var body = JsonDocument.Parse(bodyText).RootElement;
            var expectedBody = JsonDocument.Parse("{\"test\":{\"content\":\"<file content>\",\"content_type\":\"text/plain\",\"filename\":\"test.txt\",\"size\":14}}").RootElement;
            Assert.Equal(expectedBody.GetRawText(), body.GetRawText());
        }


